    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // Scene setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B0000 }); // Red roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.7 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // Ground
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeometry, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // House Group
        const houseGroup = new THREE.Group();

        // Main Body
        const bodyGeometry = new THREE.BoxGeometry(6, 4, 6);
        const body = new THREE.Mesh(bodyGeometry, wallMaterial);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeometry = new THREE.ConeGeometry(5, 3, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeometry = new THREE.BoxGeometry(1.5, 1.5, 0.2);
        const leftWindow = new THREE.Mesh(windowGeometry, windowMaterial);
        leftWindow.position.set(-1.5, 2.5, 2.9);
        leftWindow.castShadow = true;
        houseGroup.add(leftWindow);

        const rightWindow = new THREE.Mesh(windowGeometry, windowMaterial);
        rightWindow.position.set(1.5, 2.5, 2.9);
        rightWindow.castShadow = true;
        houseGroup.add(rightWindow);

        // Door
        const doorGeometry = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeometry, doorMaterial);
        door.position.set(0, 1.25, 2.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Chimney
        const chimneyGeometry = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimneyGeometry, wallMaterial);
        chimney.position.set(0, 6, 0.5);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        // Porch
        const porchGeometry = new THREE.BoxGeometry(6, 0.5, 2);
        const porch = new THREE.Mesh(porchGeometry, new THREE.MeshStandardMaterial({ color: 0x654321 }));
        porch.position.set(0, 0.25, 3);
        porch.castShadow = true;
        houseGroup.add(porch);

        // Roof over porch
        const porchRoofGeometry = new THREE.BoxGeometry(6.5, 0.5, 2.5);
        const porchRoof = new THREE.Mesh(porchRoofGeometry, roofMaterial);
        porchRoof.position.set(0, 3.5, 3);
        porchRoof.castShadow = true;
        houseGroup.add(porchRoof);

        scene.add(houseGroup);

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
